```hcl
resource "aws_lb" "<example_resource_name>" {
  subnets = ["<example_subnet_id_1>", "<example_subnet_id_2>"]

  enable_deletion_protection = true # Critical: enables deletion protection to pass the check
}
```

```hcl
# Terraform: enable ALB access logs to S3
resource "aws_lb" "<example_resource_name>" {
  name            = "<example_resource_name>"
  security_groups = ["<example_security_group_id>"]
  subnets         = ["<subnet_id_1>", "<subnet_id_2>"]

  access_logs {
    bucket  = "<example_resource_name>"  # critical: destination S3 bucket for logs
    enabled = true                        # critical: enable ALB access logging
  }
}
```

```hcl
# Terraform: Managed policy without '*:*' admin privileges
resource "aws_iam_policy" "<example_resource_name>" {
  name   = "<example_resource_name>"
  policy = jsonencode({
    Version   = "2012-10-17"
    Statement = [{
      Effect   = "Allow"
      Action   = "iam:GetUser"  # CRITICAL: not "*" or "*:*"; removes admin privileges
      Resource = "*"             # CRITICAL: paired with specific action to avoid full admin
    }]
  })
}
```

```hcl
resource "aws_iam_account_password_policy" "<example_resource_name>" {
  minimum_password_length = 14  # Critical: enforces minimum password length >=14
}
```

